#### 方法一：组合数学

**思路与算法**

题目要求我们构造长度为 $n$ 的数组，其中每个数字都在 $[1,m]$ 中，并且恰好有 $k$ 对相邻元素相同，求可以构造多少个这样的数组。

首先，长度为 $n$ 的数组中共有 $n-1$ 对相邻元素，其中需要有 $k$ 对相邻元素相同，剩下的 $n-1-k$ 对相邻元素不同。我们可以把这 $n-1-k$ 对不同的相邻元素看作隔板，将整个数组分隔为 $n-k$ 段子数组，每段子数组的元素都相同。我们可以先分隔数组，然后再填入数字。接下来计算方案数：

1. 在 $n-1$ 个空位中选择 $n-1-k$ 个插入隔板，共有 $\binom{n-1}{n-1-k}=\binom{n-1}{k}$ 种方案。
2. 第一段中所有元素都一样，且取值没有限制，所以第一段有 $m$ 种。
3. 第二段以及后面的所有段需要和前一段取值不同，有 $m-1$ 种取值。共有 $n-k-1$ 段，所以有 $(m-1)^{n-k-1}$ 种。

综上，根据乘法原理，答案是 $m\times \binom{n-1}{k}\times (m-1)^{n-1-k}$。要计算这个式子，需要使用组合数公式 $\binom{a}{b}=\frac{a!}{b!\times(a-b)!}$ 与 [线性求逆元公式](https://oi-wiki.org/math/number-theory/inverse/)，以及 [快速幂](https://oi-wiki.org/math/binary-exponentiation/)。

**代码**

```C++ [sol1-C++]
const int MOD = 1e9 + 7;
const int MX = 1e5;

long long fact[MX];
long long inv_fact[MX];

class Solution {
    long long qpow(long long x, int n) {
        long long res = 1;
        while (n) {
            if (n & 1) {
                res = res * x % MOD;
            }
            x = x * x % MOD;
            n >>= 1;
        }
        return res;
    }

    long long comb(int n, int m) {
        return fact[n] * inv_fact[m] % MOD * inv_fact[n - m] % MOD;
    }
    void init() {
        if (fact[0]) {
            return;
        }
        fact[0] = 1;
        for (int i = 1; i < MX; i++) {
            fact[i] = fact[i - 1] * i % MOD;
        }

        inv_fact[MX - 1] = qpow(fact[MX - 1], MOD - 2);
        for (int i = MX - 1; i; i--) {
            inv_fact[i - 1] = inv_fact[i] * i % MOD;
        }
    }

public:
    int countGoodArrays(int n, int m, int k) {
        init();
        return comb(n - 1, k) * m % MOD * qpow(m - 1, n - k - 1) % MOD;
    }
};
```

```Java [sol1-Java]
class Solution {
    static final int MOD = (int)1e9 + 7;
    static final int MX = 100000;
    static long[] fact = new long[MX];
    static long[] invFact = new long[MX];

    static long qpow(long x, int n) {
        long res = 1;
        while (n > 0) {
            if ((n & 1) == 1) {
                res = res * x % MOD;
            }
            x = x * x % MOD;
            n >>= 1;
        }
        return res;
    }

    static {
        fact[0] = 1;
        for (int i = 1; i < MX; i++) {
            fact[i] = fact[i - 1] * i % MOD;
        }
        invFact[MX - 1] = qpow(fact[MX - 1], MOD - 2);
        for (int i = MX - 1; i > 0; i--) {
            invFact[i - 1] = invFact[i] * i % MOD;
        }
    }

    long comb(int n, int m) {
        return fact[n] * invFact[m] % MOD * invFact[n - m] % MOD;
    }

    public int countGoodArrays(int n, int m, int k) {
        return (int)(comb(n - 1, k) * m % MOD * qpow(m - 1, n - k - 1) % MOD);
    }
}
