```TypeScript [sol1-TypeScript]
const MOD: bigint = BigInt(1e9 + 7);
const MX: number = 100000;

const fact: bigint[] = new Array(MX).fill(0n);
const invFact: bigint[] = new Array(MX).fill(0n);
